mapper.select:
SELECT * FROM ( SELECT ROWNUM AS rn, t.* FROM ( SELECT mc.member_coupon_id AS memberCouponId, mc.coupon_id AS couponId, c.coupon_name AS couponName, c.partner_id AS partnerId, p.partner_name AS partnerName, mc.member_id AS memberId, c.discount_type AS discountType, c.discount_amount AS discountAmount, TO_CHAR(mc.issued_at, 'YYYY-MM-DD') AS issuedAt, TO_CHAR(c.valid_until, 'YYYY-MM-DD') AS validUntil, mc.status FROM member_coupon mc JOIN coupon c ON mc.member_coupon_id = c.coupon_id LEFT JOIN partner p ON c.partner_id = p.partner_id
AND mc.status = #{status}
AND c.coupon_name LIKE '%' || #{couponKeyword} || '%'
AND mc.member_id = #{memberKeyword}
ORDER BY mc.issued_at DESC ) t WHERE ROWNUM <= #{endRow} ) WHERE rn >= #{startRow}

